  if (segment.includes(",")) {
    const values = segment.split(",").flatMap((part) => parseSegment(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  const num = parseInt(segment, 10);
  if (isNaN(num)) throw new Error(`Invalid cron value: ${segment}`);
  if (num < min || num > max)
    throw new Error(`Value ${num} out of range (${min}-${max})`);
  return [num];
};

const parseCron = (expression: string): CronResult => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const fieldOrder: [string, CronField][] = [
    [minuteStr, "minute"],
    [hourStr,   "hour"],
    [domStr,    "dayOfMonth"],
    [monthStr,  "month"],
    [dowStr,    "dayOfWeek"],
  ];

  const result = {} as CronResult;

  for (const [value, field] of fieldOrder) {
    const { min, max } = FIELD_RANGES[field];
    let parsed = parseSegment(value, min, max);

    // Normalize dayOfWeek: treat 7 as 0 (Sunday)
    if (field === "dayOfWeek") {
      parsed = [...new Set(parsed.map((v) => (v === 7 ? 0 : v)))].sort((a, b) => a - b);
    }

    result[field] = parsed;
  }

  return result;
};

export default parseCron;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof CronExpression;

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, field: string): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step value "${stepStr}" in field "${field}"`);

    const [start, end] = rangePart === "*"
      ? [min, max]
      : rangePart.includes("-")
        ? rangePart.split("-").map(Number) as [number, number]
        : [parseInt(rangePart, 10), max];

    assertInRange(start, min, max, field);
    assertInRange(end,   min, max, field);
    if (start > end) throw new RangeError(`Invalid range ${start}-${end} in field "${field}"`);

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    if (isNaN(start) || isNaN(end)) throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    assertInRange(start, min, max, field);
    assertInRange(end,   min, max, field);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(raw: string, min: number, max: number, field: string): number[] {
  const values = raw
    .split(",")
    .flatMap(segment => parseSegment(segment.trim(), min, max, field));

  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);
  }

  return Object.fromEntries(
    FIELD_ORDER.map((field, i) => {
      const [min, max] = FIELD_RANGES[field];
      return [field, parseField(fields[i], min, max, field)];
    })
  ) as CronExpression;
}

type CronField = {
  min: number;
  max: number;
};

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELDS: [keyof CronResult, CronField][] = [
  ["minute",     { min: 0,  max: 59 }],
  ["hour",       { min: 0,  max: 23 }],
  ["dayOfMonth", { min: 1,  max: 31 }],
  ["month",      { min: 1,  max: 12 }],
  ["dayOfWeek",  { min: 0,  max: 6  }],
];

function range(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = field;

  const validate = (n: number, label: string): number => {
    if (!Number.isInteger(n) || n < min || n > max)
      throw new RangeError(`${label} value ${n} out of range [${min}, ${max}]`);
    return n;
  };

  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = Number(stepStr);
    if (!Number.isInteger(step) || step < 1)
      throw new SyntaxError(`Invalid step value: "${stepStr}"`);

    if (left === "*") return range(min, max, step);

    if (left.includes("-")) {
      const [fromStr, toStr] = left.split("-");
      const from = validate(Number(fromStr), "Range start");
      const to   = validate(Number(toStr),   "Range end");
      if (from > to) throw new RangeError(`Range start ${from} > end ${to}`);
      return range(from, to, step);
    }

    const start = validate(Number(left), "Step base");
    return range(start, max, step);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [fromStr, toStr] = segment.split("-");
    const from = validate(Number(fromStr), "Range start");
    const to   = validate(Number(toStr),   "Range end");
    if (from > to) throw new RangeError(`Range start ${from} > end ${to}`);
    return range(from, to);
  }

  // Single number
  const n = Number(segment);
  if (Number.isNaN(n)) throw new SyntaxError(`Invalid cron token: "${segment}"`);
  return [validate(n, "Value")];
}

function parseField(expr: string, field: CronField): number[] {
  const values = expr
    .split(",")
    .flatMap(segment => parseSegment(segment.trim(), field));

  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new SyntaxError(`Expected 5 cron fields, got ${parts.length}: "${expression}"`);

  return Object.fromEntries(
    FIELDS.map(([name, field], i) => [name, parseField(parts[i], field)])
  ) as CronResult;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Step value: */N or start-end/N
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in segment: ${segment}`);
    }

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = clamp(parseInt(startStr, 10), min, max);
      const end = clamp(parseInt(endStr, 10), min, max);
      if (start > end) throw new Error(`Invalid range: ${rangePart}`);
      base = range(start, end);
    } else {
      const start = clamp(parseInt(rangePart, 10), min, max);
      base = range(start, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new Error(`Invalid range: ${segment}`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron segment: ${segment}`);
  return [clamp(value, min, max)];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    for (const value of parseSegment(segment.trim(), field)) {
      values.add(value);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const trimmed = expression.trim().replace(/\s+/g, " ");
  const parts = trimmed.split(" ");

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fields: CronField[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  return fields.reduce((acc, field, i) => {
    acc[field] = parseField(parts[i], field);
    return acc;
  }, {} as CronExpression);
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function expandField(expr: string, min: number, max: number): number[] {
  // Comma-separated list — recurse on each part
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => expandField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map((n) => parseInt(n, 10));
        rangeMin = clamp(lo, min, max);
        rangeMax = clamp(hi, min, max);
      } else {
        rangeMin = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [loStr, hiStr] = expr.split("-");
    const lo = clamp(parseInt(loStr, 10), min, max);
    const hi = clamp(parseInt(hiStr, 10), min, max);
    if (lo > hi) {
      throw new RangeError(`Invalid range: ${lo}-${hi}`);
    }
    return Array.from({ length: hi - lo + 1 }, (_, i) => lo + i);
  }

  // Wildcard
  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field expression: "${expr}"`);
  }
  return [clamp(value, min, max)];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return Object.fromEntries(
    fields.map((field, i) => {
      const [min, max] = FIELD_RANGES[field];
      return [field, expandField(exprs[i], min, max)];
    })
  ) as CronFields;
}
